        self.check_root()
        if not self.is_anonshield_active():
            console_print("[bold red]Error: Who Watches Watchers? transparent proxying is not active. Start it first with 'anonshield start'.[/bold red]")
            return
            
        console_print("[bold cyan]🔄 Requesting new anonymous circuit and IP address...[/bold cyan]")
        if self.trigger_new_identity():
            console_print("[green]✓ Circuit signal sent successfully.[/green]")
            if HAS_RICH:
                with Status("[cyan]Waiting for Tor exit nodes to rotate and establish a new circuit...[/cyan]", console=self.console) as status:
                    time.sleep(5)
            else:
                time.sleep(5)
            self.print_status()
            self.send_notification("Who Watches Watchers?", "New Anonymous Identity Established!")
        else:
            console_print("[bold red]✗ Failed to request new circuit. Is Tor ControlPort accessible?[/bold red]")

    def handle_mac_manual(self, iface, action):
        self.check_root()
        interfaces = self.get_interfaces()
        if iface not in interfaces:
            console_print(f"[bold red]Interface '{iface}' not found. Available interfaces: {', '.join(interfaces)}[/bold red]")
            return
            
        if action == "random":
            orig_mac = self.get_mac(iface)
            console_print(f"Spoofing MAC of [bold]{iface}[/bold] (original: {orig_mac})...", "cyan")
            subprocess.run(["ip", "link", "set", "dev", iface, "down"], capture_output=True)
            res = subprocess.run(["macchanger", "-r", iface], capture_output=True, text=True)
            subprocess.run(["ip", "link", "set", "dev", iface, "up"], capture_output=True)
            new_mac = self.get_mac(iface)
            console_print(f"[green]✓ MAC updated to: {new_mac}[/green]")
            
        elif action == "reset":
            console_print(f"Resetting MAC of [bold]{iface}[/bold] to default/permanent...", "cyan")
            subprocess.run(["ip", "link", "set", "dev", iface, "down"], capture_output=True)
            subprocess.run(["macchanger", "-p", iface], capture_output=True)
            subprocess.run(["ip", "link", "set", "dev", iface, "up"], capture_output=True)
            curr_mac = self.get_mac(iface)
            console_print(f"[green]✓ MAC restored to permanent hardware: {curr_mac}[/green]")


def main():
    disclaimer = (
        "\n[bold yellow]⚠️  LEGAL DISCLAIMER:[/bold yellow] "
        "[dim]Who Watches Watchers? is developed solely for educational and privacy-enhancing purposes.\n"
        "The author (Grouvya) assumes absolutely no responsibility or liability for how this tool is utilized.\n"
        "Any misuse of this application for malicious, unauthorized, or illegal activities is strictly\n"
        "prohibited and is done entirely at the user's own risk.[/dim]\n"
    )
    console_print(disclaimer)

    parser = argparse.ArgumentParser(
        description="🛡️ Who Watches Watchers? - Fully Anonymize system TCP and DNS traffic using Tor"
    )
    
    subparsers = parser.add_subparsers(dest="command", help="Who Watches Watchers? subcommands")
    
    subparsers.add_parser("start", help="Secure all outbound TCP and DNS traffic through Tor and spoof MACs")
    subparsers.add_parser("stop", help="Flush firewall rules, restore system DNS configurations, and reset MACs")
    subparsers.add_parser("status", help="Display system-wide integration and anonymity network status dashboard")
    subparsers.add_parser("newid", help="Request a new Tor circuit to change your public anonymous IP address")
    
    mac_parser = subparsers.add_parser("mac", help="Manually change or reset hardware MAC addresses")
    mac_parser.add_argument("interface", help="Target network interface (e.g. eth0, wlan0)")
    mac_parser.add_argument("action", choices=["random", "reset"], help="Action: 'random' to spoof, 'reset' to restore hardware MAC")

    sandbox_parser = subparsers.add_parser("sandbox", help="Run a specific command isolated in a Tor namespace")
    sandbox_parser.add_argument("cmd", nargs=argparse.REMAINDER, help="The command to execute in the sandbox")

    bypass_parser = subparsers.add_parser("bypass", help="Run a specific command that bypasses Tor and connects to the Clearnet")
    bypass_parser.add_argument("cmd", nargs=argparse.REMAINDER, help="The command to execute without Tor routing")

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(0)

    shield = AnonShield()

    if args.command == "start":
        shield.start_shield()
    elif args.command == "stop":
        shield.stop_shield()
    elif args.command == "status":
        shield.print_status()
    elif args.command == "newid":
        shield.rotate_identity()
    elif args.command == "mac":
        shield.handle_mac_manual(args.interface, args.action)
    elif args.command == "sandbox":
        if not args.cmd:
            console_print("[red]Please provide a command to run in the sandbox.[/red]")
        else:
            shield.sandbox_command(args.cmd)
    elif args.command == "bypass":
        if not args.cmd:
            console_print("[red]Please provide a command to run bypassing Tor.[/red]")
        else:
            shield.bypass_command(args.cmd)

if __name__ == "__main__":
    main()

