    def _poll_loop(self):
        last_ip_check = 0
        cached_tor_status = None
        is_active = False
        mac_spoof_active = False
        rx = 0
        tx = 0
        circuits = []
        
        while True:
            try:
                # Always update Tor connection progress so the UI progress bar is responsive
                service_status = "Stopped"
                res = subprocess.run(["systemctl", "is-active", "tor"], capture_output=True, text=True)
                if res.stdout.strip() == "active":
                    service_status = "Running"
                progress, summary = self.shield.get_tor_bootstrap_status()
                
                if not self.action_lock:
                    is_active = self.shield.is_anonshield_active()

                    current_time = time.time()
                    if current_time - last_ip_check > 30:
                        try:
                            cached_tor_status = self.shield.check_tor_ip_status()
                        except Exception:
                            pass
                        last_ip_check = current_time

                    mac_spoof_active = os.path.exists("/var/lib/anonshield/state.json")
                    rx = self.shield.bw_stats.get("rx", 0) / 1024
                    tx = self.shield.bw_stats.get("tx", 0) / 1024

                    # Fetch circuits
                    circuits = []
                    if is_active:
                        circuits = self.shield.get_circuits()

                tor_status = cached_tor_status
                self.root.after(0, lambda ia=is_active, ts=tor_status, ss=service_status, p=progress, s=summary, msa=mac_spoof_active, r=rx, t=tx, c=circuits: self.update_state_ui(
                    ia, ts, ss, p, s, msa, r, t, c
                ))
            except Exception as e:
                print(f"Poll loop error: {e}")
            time.sleep(1)

    def poll_system_state(self):
        threading.Thread(target=self._poll_loop, daemon=True).start()

    def animate_progress(self):
        try:
            current = self.tor_progress.get()
            target = getattr(self, '_target_progress', 0.0)
            
            diff = target - current
            if abs(diff) > 0.001:
                step = diff * 0.1
                if step > 0 and step < 0.002: step = 0.002
                if step < 0 and step > -0.002: step = -0.002
                
                new_val = current + step
                if (step > 0 and new_val > target) or (step < 0 and new_val < target):
                    new_val = target
                    
                self.tor_progress.set(new_val)
        except Exception:
            pass
        self.root.after(20, self.animate_progress)

    def update_state_ui(self, is_active, tor_status, service_status, progress, summary, mac_spoof_active, rx, tx, circuits):
        if tor_status and tor_status.get("IsTor") and is_active:
            self.status_card.configure(border_color=COLOR_SECURE)
            self.status_text_label.configure(text="SECURED", text_color=COLOR_SECURE)
            self.status_desc_label.configure(text="Your system connection is completely secured by Tor.")
            self.val_ip.configure(text=tor_status.get("IP", "Unknown"), text_color=COLOR_SECURE)
            self.val_ks.configure(text="Active (Fail-Close)", text_color=COLOR_SECURE)
        else:
            self.status_card.configure(border_color=COLOR_EXPOSED)
            self.status_text_label.configure(text="EXPOSED", text_color=COLOR_EXPOSED)
            self.status_desc_label.configure(text="Your connection is routed directly to the clearnet.")
            ip = tor_status.get("IP") if tor_status else "Retrieving..."
            self.val_ip.configure(text=ip, text_color=COLOR_EXPOSED)
            self.val_ks.configure(text="Inactive", text_color=FG_TEXT)

        tor_desc = f"{service_status} ({summary})"
        self.val_tor.configure(text=tor_desc)
        self._target_progress = progress / 100.0
        
        mac_desc = "Active (Spoofed)" if mac_spoof_active else "Default (Hardware MAC)"
        mac_color = COLOR_SECURE if mac_spoof_active else FG_TEXT
        self.val_mac.configure(text=mac_desc, text_color=mac_color)
        
        self.graph.update_graph(rx, tx)
        
        if circuits:
            # Show up to 3 active circuits
            c_str = "\n".join(circuits[:3])
            self.val_circuit.configure(text=c_str, text_color=COLOR_ONION)
        else:
            self.val_circuit.configure(text="No active circuits.", text_color=FG_MUTED)

    def on_exit_node_change(self, value):
        print(f"\n[Info]: Updating Tor Exit Node Region to: {value}")
        self.shield.set_exit_nodes(value)

    def on_obfs4_change(self):
        enable = self.obfs4_var.get()
        print(f"\n[Info]: Obfs4 Bridges {'Enabled' if enable else 'Disabled'}")
        self.shield.set_obfs4(enable)
        
    def on_mac_rotator_change(self):
        enable = self.mac_rotator_var.get()
        if enable:
            print("\n[Info]: MAC Auto-Rotator Enabled (15m interval)")
            self.shield.start_mac_rotator(15)
        else:
            print("\n[Info]: MAC Auto-Rotator Disabled")
            self.shield.stop_mac_rotator()

    def on_bypass_app(self):
        if not self.shield.is_anonshield_active():
            messagebox.showinfo("Who Watches Watchers?", "Who Watches Watchers? must be active to use Split Tunneling.")
            return
            
        self.show_split_tunnel_dialog()

    def on_hidden_service(self):
        if not self.shield.is_anonshield_active():
            messagebox.showinfo("Who Watches Watchers?", "Who Watches Watchers? must be active to host a Hidden Service.")
            return
            
        if self.active_onion:
            # Stop existing service
            self.shield.stop_hidden_service(self.active_onion.split(".")[0])
            self.active_onion = None
            self.btn_hidden.configure(text="🧅 Host Hidden Service (.onion)", fg_color=COLOR_BUTTON_BG)
            print("\n[Info] Hidden Service successfully taken offline.")
            return

        dialog = ctk.CTkInputDialog(text="Enter Local Port to expose as .onion (e.g. 8080):", title="Host Hidden Service")
        port_str = dialog.get_input()
        if not port_str: return
        
        try:
            port = int(port_str)
            print(f"\n[Info] Initiating Ephemeral Hidden Service for local port {port}...")
            onion = self.shield.start_hidden_service(port)
            if "Error" in onion:
                print(f"[Error] Failed to create hidden service: {onion}")
                return
                
            self.active_onion = onion
            self.btn_hidden.configure(text="🔴 Stop Hidden Service", fg_color=COLOR_EXPOSED)
            print(f"\n[Success] 🧅 HIDDEN SERVICE IS LIVE!\nLocal Port: {port}\nOnion URL: {onion}")
        except ValueError:
            messagebox.showerror("Error", "Port must be an integer.")

    
    def on_custom_bridges(self):
        dialog = ctk.CTkToplevel(self.root)
        dialog.title("Custom Tor Bridges")
        dialog.geometry("500x400")
        dialog.attributes("-topmost", True)
        ctk.CTkLabel(dialog, text="Paste your custom Tor Bridge lines below (one per line):", font=("Helvetica", 12, "bold")).pack(pady=(15, 5), padx=20, anchor="w")
        textbox = ctk.CTkTextbox(dialog, height=200, fg_color="#0A0A0F", border_width=1, border_color="#2D2D44")
        textbox.pack(fill="x", padx=20, pady=15)
        def save():
            bridges = [line.strip() for line in textbox.get("1.0", "end-1c").split("\n") if line.strip()]
            self.shield.set_custom_bridges(bridges)
            messagebox.showinfo("Success", "Custom bridges applied successfully.", parent=dialog)
            dialog.destroy()
        ctk.CTkButton(dialog, text="Save & Apply", command=save, fg_color="#00E5FF", text_color="#121214").pack(pady=10)

    def show_split_tunnel_dialog(self):
        dialog = ctk.CTkToplevel(self.root)
        dialog.title("Split Tunneling (Bypass Tor)")
        dialog.geometry("500x500")
        dialog.attributes("-topmost", True)
        ctk.CTkLabel(dialog, text="Select an application to launch on the Clearnet:", font=("Helvetica", 14, "bold")).pack(pady=(15, 10), padx=20, anchor="w")
        
        apps = {}
        paths = ["/usr/share/applications", os.path.expanduser("~/.local/share/applications")]
        for path in paths:
            if not os.path.exists(path): continue
            for file in os.listdir(path):
                if file.endswith(".desktop"):
                    try:
                        with open(os.path.join(path, file), "r", encoding="utf-8") as f:
                            name = ""
                            exec_cmd = ""
                            for line in f:
                                if line.startswith("Name=") and not name:
                                    name = line.strip().split("=", 1)[1]
                                elif line.startswith("Exec=") and not exec_cmd:
                                    parts = line.strip().split("=", 1)[1].split()
                                    exec_cmd = " ".join([p for p in parts if not p.startswith('%')])
                            if name and exec_cmd: apps[name] = exec_cmd
                    except: pass
                    
        scrollable_frame = ctk.CTkScrollableFrame(dialog, fg_color="#0A0A0F")
        scrollable_frame.pack(fill="both", expand=True, padx=20, pady=10)
        selected_app = ctk.StringVar(value="")
        for name in sorted(apps.keys()):
            ctk.CTkRadioButton(scrollable_frame, text=name, variable=selected_app, value=name).pack(anchor="w", pady=5)
            
        custom_frame = ctk.CTkFrame(dialog, fg_color="transparent")
        custom_frame.pack(fill="x", padx=20, pady=5)
        ctk.CTkRadioButton(custom_frame, text="Custom Command:", variable=selected_app, value="__custom__").pack(side="left")
        custom_entry = ctk.CTkEntry(custom_frame, placeholder_text="e.g. ping google.com")
        custom_entry.pack(side="left", fill="x", expand=True, padx=(10, 0))
            
        def launch():
            sel = selected_app.get()
            if not sel: return messagebox.showerror("Error", "Please select an application.", parent=dialog)
            cmd_str = custom_entry.get().strip() if sel == "__custom__" else apps.get(sel, "")
            if cmd_str:
                threading.Thread(target=lambda: self.shield.bypass_command(cmd_str.split()), daemon=True).start()
                messagebox.showinfo("Success", f"Launched on Clearnet: {cmd_str}", parent=dialog)
                dialog.destroy()
        ctk.CTkButton(dialog, text="Launch (Bypass)", command=launch, fg_color="#F59E0B", text_color="#121214").pack(pady=15)

    def on_start_shield(self):
        if self.action_lock: return
        if self.shield.is_anonshield_active():
            messagebox.showinfo("Who Watches Watchers?", "Who Watches Watchers? Transparent Proxy is already active.")
            return

        self.set_controls_state(False)
        self.console_widget.configure(state='normal')
        self.console_widget.delete('1.0', tk.END)
        self.console_widget.configure(state='disabled')
        
        def run():
            try:
                self.shield.start_shield()
            except Exception as e:
                print(f"\n[Error]: {e}")
            finally:
                self.root.after(0, lambda: self.set_controls_state(True))
                
        threading.Thread(target=run, daemon=True).start()

    def on_stop_shield(self):
        if self.action_lock: return
        if not self.shield.is_anonshield_active():
            messagebox.showinfo("Who Watches Watchers?", "Who Watches Watchers? Anonymizer is already offline.")
            return

        self.set_controls_state(False)
        
        def run():
            try:
                self.shield.stop_shield()
                if self.active_onion:
                    self.active_onion = None
                    self.root.after(0, lambda: self.btn_hidden.configure(text="🧅 Host Hidden Service (.onion)", fg_color=COLOR_BUTTON_BG))
            except Exception as e:
                print(f"\n[Error]: {e}")
            finally:
                self.root.after(0, lambda: self.set_controls_state(True))
                
        threading.Thread(target=run, daemon=True).start()

    def on_check_tor(self):
        try:
            print("\n[Info] Opening Tor Check website in default browser...")
            webbrowser.open("https://check.torproject.org/")
        except Exception as e:
            print(f"\n[Error] Failed to open browser: {e}")

    def on_new_identity(self):
        if self.action_lock: return
        if not self.shield.is_anonshield_active():
            messagebox.showerror("Error", "Start Who Watches Watchers? anonymization first before requesting a new circuit.")
            return

        self.set_controls_state(False)
        
        def run():
            try:
                self.shield.rotate_identity()
            except Exception as e:
                print(f"\n[Error]: {e}")
            finally:
                self.root.after(0, lambda: self.set_controls_state(True))
                
        threading.Thread(target=run, daemon=True).start()


def main():
    root = ctk.CTk()
    app = AnonShieldGUI(root)
    root.mainloop()

if __name__ == "__main__":
    main()

