f+wf+jHQwghhPAjJhoAIYQQwr8OP4z/pkexH0II\nIfwYiwZACCGE8JPhB/lvfhT4IYQQQgghhBBCCCGEEEIIIYQQQgghhBBCCCGEEEIIIYQQQgghhBBC\nCCGEEEIIIYQQQgghhBBCCCGEEEIIIYQQQgghhBBCCCGEEEIIIYQQQgghhBBCCCGEEEIIIYQQQggh\nhBBCCCGEEEIIIYQQQgghhBBCCCGEEEIIIYQQQgghhBBCCCGEEEIIIYQQQgghhBBCCCGEEEIIIYQQ\nQgghhBBCCCGEEEIIIYQQQgghhBBCCCGEEEIIIYQQQgghhBBCCCGEEEIIIYQQQgghhBBCCCGEEEII\nIYQQQgghhBBCCCGEEEIIIYQQQgghhBBCCCGEEEIIIYQQQgghhBBCCCGEEEIIIYQQQgghhBBCCCGE\nEEIIIYQQQgghhBBCCCGEEEIIIYQQQgghhBBCCCGEEEIIIYQQQgghhBBCCCGEEEIIIYQQQgghhBBC\nCCGEEEIIIYQQQgghhBBCCCGEEEIIIYQQQgghhBBCCCGEEEIIIYQQQgghhBBCCCGEEEIIIYQQQggh\nhBBCCCGEEEIIIYQQQgghhBBCCCGEEEIIIYQQQgghhBBCCCGEEEIIIYQQQgghhBBCCCGEEEIIIYQQ\nQgghhBBCCCGEEEIIIYQQQgghhBBCCCGEEEIIIYQQQgghhBBCCCGEEEIIIYQQQgghhBBCCCGEEEII\nIYQQQgghhBBCCCGEEEIIIYQQQgghhBBCCCGEEEIIIYQQQgghhBBCCCGEEEIIIYQQQgghhBBCCCGE\nEEIIIYQQQgghhBBCCCGEEEIIIYQQQgghhBBCCCGEEEIIIYQQQgghhBBCCCGEEEIIIYQQQgghhBBC\nCCGEEEIIIYQQQgghhBBCCCGEEEIIIYQQQgghhBBCCCGEEEIIIYQQQhiIiPz/AbX65gya4HErAAAA\nAElFTkSuQmCC" | base64 -d > "/tmp/anonshield_icon.png"

    
    # Now install from /tmp
    TOR_USER="tor"
    if getent passwd debian-tor > /dev/null 2>&1; then
        TOR_USER="debian-tor"
    fi

    cp "/tmp/anonshield.conf" "$CONF_DIR/anonshield.conf"
    if grep -q "^tor_user" "$CONF_DIR/anonshield.conf"; then
        sed -i "s/^tor_user\s*=.*/tor_user = $TOR_USER/" "$CONF_DIR/anonshield.conf"
    else
        echo "tor_user = $TOR_USER" >> "$CONF_DIR/anonshield.conf"
    fi
    chmod 600 "$CONF_DIR/anonshield.conf"
    echo -e "  ${GREEN}✓${NC} Configured settings in $CONF_DIR/anonshield.conf (Detected Tor User: $TOR_USER)"

    cp "/tmp/anonshield.py" "$APP_DIR/anonshield.py"
    chmod +x "$APP_DIR/anonshield.py"
    ln -sf "$APP_DIR/anonshield.py" "$BIN_LINK"
    echo -e "  ${GREEN}✓${NC} Installed executable binary to $BIN_LINK"

    cp "/tmp/anonshield_gui.py" "$APP_DIR/anonshield_gui.py"
    chmod +x "$APP_DIR/anonshield_gui.py"
    
    # Create wrapper script for venv
    cat << 'EOF_WRAP' > "/usr/local/bin/anonshield-gui"
#!/bin/bash
/opt/anonshield/venv/bin/python /opt/anonshield/anonshield_gui.py
EOF_WRAP
    chmod +x "/usr/local/bin/anonshield-gui"

    echo -e "  ${GREEN}✓${NC} Installed GUI binary to /usr/local/bin/anonshield-gui"

    cp "/tmp/anonshield_icon.png" "$APP_DIR/icon.png"
    mkdir -p /usr/share/icons/hicolor/256x256/apps
    cp "/tmp/anonshield_icon.png" "/usr/share/icons/hicolor/256x256/apps/anonshield.png"
    echo -e "  ${GREEN}✓${NC} Installed icon file."

    cp "/tmp/com.anonshield.policy" "/usr/share/polkit-1/actions/com.anonshield.policy"
    echo -e "  ${GREEN}✓${NC} Installed PolicyKit action rule."
    
    # Cleanup tmp files
    rm -f /tmp/anonshield.conf /tmp/anonshield.py /tmp/anonshield_gui.py /tmp/anonshield_icon.png /tmp/com.anonshield.policy

    # 7. Create Launchers and Shortcuts
    echo -e "\n${BOLD}${BLUE}[5/6]${NC} Deploying Application Menu and Desktop launchers..."

    CAT_MENU="/usr/share/applications/anonshield.desktop"
    cat << EOF > "$CAT_MENU"
[Desktop Entry]
Name=Who Watches Watchers? Security Center
Comment=Secure system-wide network connection using Tor
Exec=sh -c "xhost +si:localuser:root && pkexec env DISPLAY=\$DISPLAY XAUTHORITY=\$XAUTHORITY /usr/local/bin/anonshield-gui"
Icon=/opt/anonshield/icon.png
Terminal=false
Type=Application
Categories=Network;Security;System;
StartupNotify=true
EOF
    chmod 644 "$CAT_MENU"
    echo -e "  ${GREEN}✓${NC} Created System Application Menu shortcut"

    if [ -d "$REAL_HOME/Desktop" ]; then
      DESKTOP_SHORTCUT="$REAL_HOME/Desktop/AnonShield.desktop"
      cat << EOF > "$DESKTOP_SHORTCUT"
[Desktop Entry]
Name=Who Watches Watchers?
Comment=System-Wide Tor Anonymizer GUI
Exec=sh -c "xhost +si:localuser:root && pkexec env DISPLAY=\$DISPLAY XAUTHORITY=\$XAUTHORITY /usr/local/bin/anonshield-gui"
Icon=/opt/anonshield/icon.png
Terminal=false
Type=Application
Categories=Network;Security;System;
StartupNotify=true
EOF
      chown "$REAL_USER:$REAL_USER" "$DESKTOP_SHORTCUT"
      chmod +x "$DESKTOP_SHORTCUT"
      echo -e "  ${GREEN}✓${NC} Created Desktop Launcher"
    fi

    # 8. Deploy Systemd Service
    echo -e "\n${BOLD}${BLUE}[6/7]${NC} Deploying systemd service..."
    SERVICE_FILE="/etc/systemd/system/anonshield.service"
    cat << 'EOF' > "$SERVICE_FILE"
[Unit]
Description=Who Watches Watchers? Transparent Proxy
After=network.target tor.service

[Service]
Type=oneshot
RemainAfterExit=yes
ExecStart=/usr/local/bin/anonshield start
ExecStop=/usr/local/bin/anonshield stop

[Install]
WantedBy=multi-user.target
EOF
    systemctl daemon-reload
    echo -e "  ${GREEN}✓${NC} Deployed systemd service"

    # 9. Complete Verification
    echo -e "\n${BOLD}${BLUE}[7/7]${NC} Verifying installation sanity..."
    if [ -f "$BIN_LINK" ] && [ -x "$BIN_LINK" ]; then
      echo -e "  ${GREEN}✓${NC} Verification successful! Binaries are active."
    else
      echo -e "  ${RED}✗${NC} Verification failed. Core binaries are invalid or missing."
      exit 1
    fi

    echo -e "\n${BOLD}${GREEN}=======================================================${NC}"
    echo -e "${BOLD}${GREEN}      🛡️  WHO WATCHES WATCHERS? HAS BEEN INSTALLED!     ${NC}"
    echo -e "${BOLD}${GREEN}=======================================================${NC}"
    echo -e "You can now run and manage the software using standard commands:\n"
    echo -e "  • ${BOLD}sudo anonshield start${NC}    - Initiate transparent proxy and secure connection (CLI)"
    echo -e "  • ${BOLD}sudo anonshield status${NC}   - View current routing details and IP information (CLI)"
    echo -e "  • ${BOLD}sudo anonshield newid${NC}    - Request a new anonymous circuit and external IP (CLI)"
    echo -e "  • ${BOLD}sudo anonshield stop${NC}     - Safely revert network and disable proxy (CLI)"
    echo -e "\n${BOLD}💻 Graphical Interface Available:${NC}"
    echo -e "  • Run ${BOLD}pkexec anonshield-gui${NC} from any terminal\n"
    echo -e "To uninstall completely, run: ${BOLD}sudo $0 --uninstall${NC}\n"
    echo -e "Have an incredibly secure and private session!\n"
}

# Parse Arguments
if [[ "$1" == "--uninstall" ]] || [[ "$1" == "uninstall" ]]; then
    do_uninstall
elif [[ "$1" == "--install" ]] || [[ "$1" == "install" ]] || [[ -z "$1" ]]; then
    do_install
else
    echo -e "${RED}Unknown argument: $1${NC}"
    echo -e "Usage: $0 [--install | --uninstall]"
    exit 1
fi
